const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const app = express();

app.use(express.json());

const esClient = new Client({
  node: process.env.ELASTICSEARCH_NODE || 'http://localhost:9200',
  auth: {
    username: process.env.ELASTICSEARCH_USERNAME,
    password: process.env.ELASTICSEARCH_PASSWORD
  }
});

const ALLOWED_INDICES = process.env.ALLOWED_INDICES?.split(',') || [];

const validateIndex = (index) => {
  if (!index || typeof index !== 'string') return false;
  if (ALLOWED_INDICES.length > 0 && !ALLOWED_INDICES.includes(index)) return false;
  return true;
};

const validateQuery = (query) => {
  if (!query || typeof query !== 'object') return false;
  return true;
};

app.post('/search/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { query } = req.body;

    if (!validateIndex(index)) {
      return res.status(403).json({ error: 'Index not allowed' });
    }

    if (!validateQuery(query)) {
      return res.status(400).json({ error: 'Invalid query format' });
    }

    const result = await esClient.search({
      index,
      body: query
    });

    res.json(result.body);
  } catch (error) {
    console.error('Elasticsearch search error:', error);
    res.status(500).json({ error: 'Search failed' });
  }
});

app.listen(3000, () => {
  console.log('Elasticsearch API server running on port 3000');
});